import { LitElement, html, css, TemplateResult, unsafeCSS } from 'lit';
import { customElement, property, state } from 'lit/decorators.js';
import {
  HomeAssistant,
  LovelaceCardEditor,
  BackgroundGraphEntitiesConfig,
  EntityConfig,
  ColorThreshold,
} from './types';
import { localize } from './localize';
import { fireEvent } from './utils';
import editorStyles from './styles/editor.styles.scss';
import { HexBase } from 'vanilla-colorful/lib/entrypoints/hex';

// Conditionally define the hex-color-picker to avoid registration conflicts when another card also uses it.
if (!window.customElements.get('hex-color-picker')) {
  window.customElements.define('hex-color-picker', class extends HexBase {});
}

type EditorInternalConfig = Omit<BackgroundGraphEntitiesConfig, 'entities' | 'color_thresholds'> & {
  entities: EntityConfig[];
  color_thresholds?: ColorThreshold[];
};

interface ValueChangedEventTarget extends HTMLElement {
  configValue?: keyof EditorInternalConfig;
  value: string | number;
  type?: string;
  checked?: boolean;
}

interface ColorPicker extends HTMLElement {
  configValue?: keyof EditorInternalConfig;
}

type ThresholdEventTarget = HTMLElement & { value?: string };

@customElement('background-graph-entities-editor')
export class BackgroundGraphEntitiesEditor extends LitElement implements LovelaceCardEditor {
  @property({ attribute: false }) public hass!: HomeAssistant;
  @state() private _config: EditorInternalConfig = {
    type: 'custom:background-graph-entities',
    entities: [],
    color_thresholds: [],
  };
  @state() private _draggedIndex: number | null = null;
  @state() private _dropIndex: number | null = null;
  @state() private _draggedThresholdIndex: number | null = null;
  @state() private _dropThresholdIndex: number | null = null;
  @state() private _activeColorPicker: string | null = null;
  @state() private _editingIndex: number | null = null;

  public setConfig(config: BackgroundGraphEntitiesConfig): void {
    const entities = (config.entities || []).filter(Boolean).map((e) => (typeof e === 'string' ? { entity: e } : e));

    this._config = {
      ...config,
      entities,
    };
    this.requestUpdate();
  }

  connectedCallback(): void {
    super.connectedCallback();
    document.addEventListener('mousedown', this._handleOutsideClick);
  }

  disconnectedCallback(): void {
    super.disconnectedCallback();
    document.removeEventListener('mousedown', this._handleOutsideClick);
  }

  private _handleOutsideClick = (ev: MouseEvent): void => {
    if (!this._activeColorPicker) return;

    const target = ev.composedPath()[0] as HTMLElement;

    // If the click was on any trigger or inside any popup, do nothing.
    if (target.closest('.color-input-wrapper') || target.closest('.color-picker-popup')) {
      return;
    }

    // Otherwise, the click was outside, so close the picker.
    this._closeActiveColorPicker();
  };

  private _closeActiveColorPicker(): void {
    if (!this._activeColorPicker) return;
    const popups = this.renderRoot.querySelectorAll<HTMLElement>('.color-picker-popup');
    popups.forEach((p) => (p.style.display = 'none'));
    this._activeColorPicker = null;
  }

  private _updateEntityOrGlobalConfig(
    entityIndex: number | null,
    updater: (
      conf: Partial<EditorInternalConfig> | Partial<EntityConfig>,
    ) => Partial<EditorInternalConfig> | Partial<EntityConfig>,
  ): void {
    this._updateConfig((config) => {
      if (entityIndex === null) {
        return updater(config) as EditorInternalConfig;
      } else {
        const newEntities = [...config.entities];
        newEntities[entityIndex] = updater(newEntities[entityIndex]) as EntityConfig;
        return { ...config, entities: newEntities };
      }
    });
  }

  private _updateConfig(updater: (config: EditorInternalConfig) => EditorInternalConfig): void {
    if (!this._config) return;
    const newConfig = updater(this._config);
    this._config = newConfig;
    fireEvent(this, 'config-changed', { config: newConfig as BackgroundGraphEntitiesConfig });
  }

  private _toggleColorPicker(ev: MouseEvent, pickerId: string): void {
    ev.stopPropagation();
    const targetPopup = this.renderRoot.querySelector<HTMLElement>(`.color-picker-popup[data-picker-id="${pickerId}"]`);
    if (!targetPopup) return;

    const isVisible = this._activeColorPicker === pickerId;

    // Hide all popups first
    this._closeActiveColorPicker();

    // If the target was not visible, show it.
    if (!isVisible) {
      targetPopup.style.display = 'block';
      this._activeColorPicker = pickerId;
    }
  }

  private _handleColorModeChange(ev: Event, entityIndex: number | null = null): void {
    const newMode = (ev.target as HTMLSelectElement).value;

    this._updateEntityOrGlobalConfig(entityIndex, (conf) => {
      const oldMode = (conf.color_thresholds?.length ?? 0) > 0 ? 'threshold' : 'single';
      if (newMode === oldMode) return conf;

      const newConf = { ...conf };
      if (newMode === 'threshold') {
        if (entityIndex !== null) {
          delete (newConf as Partial<EntityConfig>).line_color;
        }
        if (!newConf.color_thresholds || newConf.color_thresholds.length === 0) {
          newConf.color_thresholds = [{ value: 0, color: '#000000' }];
        }
      } else {
        delete newConf.color_thresholds;
      }
      return newConf;
    });
  }

  private _valueChanged(ev: Event): void {
    const target = ev.target as ValueChangedEventTarget;
    const configValue = target.configValue;
    if (!configValue || !this._config) return;

    this._updateConfig((config) => {
      const newConfig = { ...config };
      let value: string | number | boolean | undefined;

      if (target.tagName?.toLowerCase() === 'ha-switch') {
        value = target.checked;
      } else {
        value = target.value;
      }

      if (target.type === 'number') {
        value = target.value === '' ? undefined : Number(target.value);
      }

      if (value === undefined || (typeof value === 'number' && isNaN(value))) {
        delete newConfig[configValue];
      } else {
        newConfig[configValue] = value;
      }
      return newConfig;
    });
  }

  private _entitySwitchChanged(ev: Event): void {
    const target = ev.target as HTMLInputElement;
    const index = Number((target as HTMLElement).dataset.index);
    const field = target.dataset.field as keyof EntityConfig;

    if (isNaN(index) || !field) return;

    const isChecked = target.checked;

    this._updateEntityOrGlobalConfig(index, (entityConf) => {
      const newEntityConf = { ...entityConf };
      (newEntityConf as Partial<EntityConfig>)[field] = isChecked as never;
      return newEntityConf;
    });
  }

  private _entityAttributeChanged(ev: Event): void {
    const target = ev.target as HTMLElement & { value?: string; type?: string };
    const index = Number(target.dataset.index);
    const field = target.dataset.field as keyof EntityConfig;

    if (isNaN(index) || !field) return;

    let value: string | number | undefined = (ev as CustomEvent).detail?.value ?? target.value;

    if (target.tagName.toLowerCase() === 'ha-slider' || target.type === 'number') {
      value = target.value === '' ? undefined : Number(target.value);
    }

    this._updateEntityOrGlobalConfig(index, (entityConf) => {
      const newEntityConf = { ...entityConf };
      if (value === '' || value === undefined || (typeof value === 'number' && isNaN(value))) {
        delete (newEntityConf as Partial<EntityConfig>)[field];
      } else {
        newEntityConf[field] = value as never;
      }
      return newEntityConf;
    });
  }

  private _colorPicked(ev: CustomEvent): void {
    const target = ev.target as ColorPicker;
    const configValue = target.configValue;
    if (!configValue) return;

    const newValue = ev.detail.value;

    this._updateConfig((config) => {
      if (config[configValue] === newValue) return config;

      const newConfig = { ...config };
      if (newValue) {
        newConfig[configValue] = newValue;
      } else {
        delete newConfig[configValue];
      }
      return newConfig;
    });
  }

  private _thresholdChanged(ev: Event, thresholdIndex: number, entityIndex: number | null = null): void {
    const target = ev.target as ThresholdEventTarget;
    const field = target.dataset.field as keyof ColorThreshold;
    const isColorPicker = target.tagName.toLowerCase().includes('color-picker');
    const value = isColorPicker ? (ev as CustomEvent).detail.value : target.value;

    const newThresholdValue = field === 'value' ? Number(value) : value;

    this._updateEntityOrGlobalConfig(entityIndex, (conf) => {
      if (!conf.color_thresholds) return conf;
      const newThresholds = [...conf.color_thresholds];
      newThresholds[thresholdIndex] = { ...newThresholds[thresholdIndex], [field]: newThresholdValue };
      return { ...conf, color_thresholds: newThresholds };
    });
  }

  private _addThreshold(entityIndex: number | null = null): void {
    const newThreshold = { value: 0, color: '#000000' };
    this._updateEntityOrGlobalConfig(entityIndex, (conf) => {
      const newThresholds = [...(conf.color_thresholds || []), newThreshold];
      return { ...conf, color_thresholds: newThresholds };
    });
  }

  private _removeThreshold(thresholdIndex: number, entityIndex: number | null = null): void {
    this._updateEntityOrGlobalConfig(entityIndex, (conf) => {
      if (!conf.color_thresholds) return conf;
      const newThresholds = [...conf.color_thresholds];
      newThresholds.splice(thresholdIndex, 1);

      if (newThresholds.length === 0) {
        const newConf = { ...conf };
        delete newConf.color_thresholds;
        return newConf;
      }
      return { ...conf, color_thresholds: newThresholds };
    });
  }

  private _handleThresholdDragStart(ev: DragEvent, index: number): void {
    this._draggedThresholdIndex = index;
    if (ev.dataTransfer) ev.dataTransfer.effectAllowed = 'move';
  }

  private _handleThresholdDragOver(ev: DragEvent, index: number): void {
    ev.preventDefault();
    if (index !== this._draggedThresholdIndex) this._dropThresholdIndex = index;
  }

  private _handleThresholdDrop(ev: DragEvent, entityIndex: number | null = null): void {
    ev.preventDefault();
    if (this._draggedThresholdIndex === null || this._dropThresholdIndex === null) return;

    this._updateEntityOrGlobalConfig(entityIndex, (conf) => {
      if (!conf.color_thresholds) return conf;
      const newThresholds = [...conf.color_thresholds];
      const [draggedItem] = newThresholds.splice(this._draggedThresholdIndex!, 1);
      newThresholds.splice(this._dropThresholdIndex!, 0, draggedItem);
      return { ...conf, color_thresholds: newThresholds };
    });

    this._draggedThresholdIndex = null;
    this._dropThresholdIndex = null;
  }

  private _handleDragStart(ev: DragEvent, index: number): void {
    this._draggedIndex = index;
    if (ev.dataTransfer) {
      ev.dataTransfer.effectAllowed = 'move';
      // Required for Firefox to initiate drag
      ev.dataTransfer.setData('text/plain', String(index));
    }
  }

  private _handleDragOver(ev: DragEvent, index: number): void {
    ev.preventDefault();
    if (index !== this._draggedIndex) {
      this._dropIndex = index;
    }
  }

  private _handleDragLeave(): void {
    this._dropIndex = null;
  }

  private _handleDrop(ev: DragEvent): void {
    ev.preventDefault();
    if (this._draggedIndex === null || this._dropIndex === null || this._draggedIndex === this._dropIndex) {
      this._handleDragEnd();
      return;
    }

    this._updateConfig((config) => {
      const newEntities = [...config.entities];
      const [draggedItem] = newEntities.splice(this._draggedIndex!, 1);
      newEntities.splice(this._dropIndex!, 0, draggedItem);
      return { ...config, entities: newEntities };
    });

    this._handleDragEnd();
  }

  private _handleDragEnd(): void {
    this._draggedIndex = null;
    this._dropIndex = null;
  }

  private _addEntity(): void {
    this._updateConfig((config) => ({
      ...config,
      entities: [...config.entities, { entity: '' }],
    }));
  }

  private _removeEntity(index: number): void {
    this._updateConfig((config) => {
      const newEntities = [...config.entities];
      newEntities.splice(index, 1);
      return { ...config, entities: newEntities };
    });
  }

  private _overwriteAppearanceChanged(ev: Event): void {
    const target = ev.target as HTMLInputElement;
    const index = Number((target as HTMLElement).dataset.index);
    if (isNaN(index)) return;

    const isChecked = target.checked;

    this._updateEntityOrGlobalConfig(index, (entityConf) => {
      const newEntityConf = { ...entityConf };
      if (isChecked) {
        newEntityConf.overwrite_graph_appearance = true;
      } else {
        delete newEntityConf.overwrite_graph_appearance;
        delete newEntityConf.line_color;
        delete newEntityConf.line_opacity;
        delete newEntityConf.color_thresholds;
      }
      return newEntityConf;
    });
    this.requestUpdate();
  }

  private _editEntity(index: number): void {
    this._editingIndex = index;
    this.requestUpdate();
  }

  private _goBack(): void {
    this._editingIndex = null;
    this.requestUpdate();
  }

  private _renderEntityEditor(): TemplateResult {
    if (this._editingIndex === null) return html``;

    const entityConf = this._config.entities[this._editingIndex];
    if (!entityConf) return html``;

    const stateObj = this.hass.states[entityConf.entity];
    const title = entityConf.name || stateObj?.attributes.friendly_name || entityConf.entity;

    const overwriteAppearance = entityConf.overwrite_graph_appearance ?? false;
    const finalIconColor = entityConf.icon_color || 'var(--primary-text-color)';

    return html`
      <div class="header">
        <ha-icon-button @click=${this._goBack}><ha-icon icon="mdi:chevron-left"></ha-icon></ha-icon-button>
        <span class="title">${title}</span>
      </div>
      <div class="card-config">
        <ha-textfield
          .label=${localize(this.hass, 'component.bge.editor.name')}
          .value=${entityConf.name || ''}
          .configValue=${'name'}
          data-index=${this._editingIndex}
          data-field="name"
          @change=${this._entityAttributeChanged}
        ></ha-textfield>
        <ha-icon-picker
          .hass=${this.hass}
          .label=${localize(this.hass, 'component.bge.editor.icon')}
          .value=${entityConf.icon || ''}
          data-index=${this._editingIndex}
          data-field="icon"
          @value-changed=${this._entityAttributeChanged}
        ></ha-icon-picker>
        <ha-entity-picker
          .hass=${this.hass}
          .label=${localize(this.hass, 'component.bge.editor.graph_entity')}
          .value=${entityConf.graph_entity || ''}
          .helper=${localize(this.hass, 'component.bge.editor.graph_entity_helper')}
          data-index=${this._editingIndex}
          data-field="graph_entity"
          @value-changed=${this._entityAttributeChanged}
        ></ha-entity-picker>

        <ha-formfield .label=${localize(this.hass, 'component.bge.editor.show_icon')}>
          <ha-switch
            .checked=${entityConf.show_icon !== false}
            data-index=${this._editingIndex}
            data-field="show_icon"
            @change=${this._entitySwitchChanged}
          ></ha-switch>
        </ha-formfield>

        ${entityConf.graph_entity
          ? html`
              <ha-formfield .label=${localize(this.hass, 'component.bge.editor.show_graph_entity_state')}>
                <ha-switch
                  .checked=${entityConf.show_graph_entity_state === true}
                  data-index=${this._editingIndex}
                  data-field="show_graph_entity_state"
                  @change=${this._entitySwitchChanged}
                ></ha-switch>
              </ha-formfield>
            `
          : ''}
        <div
          class="color-input-wrapper"
          data-picker-id="entity_icon_color_${this._editingIndex}"
          @mousedown=${(e: MouseEvent) => this._toggleColorPicker(e, `entity_icon_color_${this._editingIndex}`)}
        >
          <ha-textfield
            .label=${localize(this.hass, 'component.bge.editor.icon_color')}
            .value=${entityConf.icon_color ?? ''}
            .placeholder=${'var(--primary-text-color)'}
            data-index=${this._editingIndex}
            data-field="icon_color"
            @change=${this._entityAttributeChanged}
          ></ha-textfield>
          <div class="color-preview" style="background-color: ${finalIconColor}"></div>
          <div
            class="color-picker-popup"
            data-picker-id="entity_icon_color_${this._editingIndex}"
            @mousedown=${(e: MouseEvent) => e.stopPropagation()}
          >
            <hex-color-picker
              .color=${finalIconColor}
              data-index=${this._editingIndex}
              data-field="icon_color"
              @color-changed=${this._entityAttributeChanged}
            ></hex-color-picker>
          </div>
        </div>

        <ha-formfield .label=${localize(this.hass, 'component.bge.editor.optional_overrides')}>
          <ha-switch
            .checked=${overwriteAppearance}
            data-index=${this._editingIndex}
            @change=${this._overwriteAppearanceChanged}
          ></ha-switch>
        </ha-formfield>

        ${overwriteAppearance ? this._renderEntityGraphAppearanceEditor(this._editingIndex) : ''}
      </div>
    `;
  }

  private _renderGraphBoundsEditor(
    config: Partial<BackgroundGraphEntitiesConfig> | Partial<EntityConfig>,
    changeHandler: (ev: Event) => void,
    index?: number,
  ): TemplateResult {
    return html`
      <div class="side-by-side">
        <ha-textfield
          .label=${localize(this.hass, 'component.bge.editor.graph_min')}
          type="number"
          .value=${config.graph_min ?? ''}
          data-field="graph_min"
          .configValue=${'graph_min'}
          data-index=${index}
          @change=${changeHandler}
        ></ha-textfield>
        <ha-textfield
          .label=${localize(this.hass, 'component.bge.editor.graph_max')}
          type="number"
          .value=${config.graph_max ?? ''}
          data-field="graph_max"
          .configValue=${'graph_max'}
          data-index=${index}
          @change=${changeHandler}
        ></ha-textfield>
      </div>
    `;
  }

  private _renderEntityGraphAppearanceEditor(index: number): TemplateResult {
    const entityConf = this._config.entities[index];
    if (!entityConf) return html``;

    const colorMode = (entityConf.color_thresholds?.length ?? 0) > 0 ? 'threshold' : 'single';
    const isDarkMode = this.hass.themes?.darkMode ?? false;
    const defaultLineColor = isDarkMode ? 'white' : 'black';
    const finalLineColor = entityConf.line_color || this._config.line_color || defaultLineColor;

    return html`
      <div class="overrides">
        <h3>${localize(this.hass, 'component.bge.editor.graph_appearance')}</h3>

        <div class="opacity-slider-container">
          <div class="label-container">
            <span>${localize(this.hass, 'component.bge.editor.line_opacity')}</span>
            <span>${Number(entityConf.line_opacity ?? this._config.line_opacity ?? 0.2).toFixed(3)}</span>
          </div>
          <ha-slider
            min="0.05"
            max="0.8"
            step="0.025"
            .value=${entityConf.line_opacity ?? this._config.line_opacity ?? 0.2}
            data-index=${index}
            data-field="line_opacity"
            @change=${this._entityAttributeChanged}
            pin
          ></ha-slider>
        </div>

        ${this._renderGraphBoundsEditor(entityConf, this._entityAttributeChanged, index)}

        <div class="dropdown-wrapper" style="margin-top: 8px;">
          <ha-dropdown
            @wa-select=${(ev: CustomEvent) => {
              const target = { value: ev.detail.item.value };
              this._handleColorModeChange({ target } as unknown as Event, index);
            }}
          >
            <div slot="trigger" class="dropdown-trigger">
              <ha-textfield
                readonly
                .label=${localize(this.hass, 'component.bge.editor.color_mode')}
                .value=${colorMode === 'single'
                  ? localize(this.hass, 'component.bge.editor.color_mode_single')
                  : localize(this.hass, 'component.bge.editor.color_mode_threshold')}
                iconTrailing
                class="dropdown-textfield"
              >
                <ha-icon slot="trailingIcon" icon="mdi:menu-down"></ha-icon>
              </ha-textfield>
            </div>
            <ha-dropdown-item value="single"
              >${localize(this.hass, 'component.bge.editor.color_mode_single')}</ha-dropdown-item
            >
            <ha-dropdown-item value="threshold"
              >${localize(this.hass, 'component.bge.editor.color_mode_threshold')}</ha-dropdown-item
            >
          </ha-dropdown>
        </div>

        ${colorMode === 'single'
          ? html`
              <div
                class="color-input-wrapper"
                data-picker-id="entity_line_color_${index}"
                @mousedown=${(e: MouseEvent) => this._toggleColorPicker(e, `entity_line_color_${index}`)}
              >
                <ha-textfield
                  .label=${localize(this.hass, 'component.bge.editor.line_color')}
                  .value=${entityConf.line_color ?? ''}
                  .placeholder=${this._config.line_color || defaultLineColor}
                  data-index=${index}
                  data-field="line_color"
                  @change=${this._entityAttributeChanged}
                ></ha-textfield>
                <div class="color-preview" style="background-color: ${finalLineColor}"></div>
                <div
                  class="color-picker-popup"
                  data-picker-id="entity_line_color_${index}"
                  @mousedown=${(e: MouseEvent) => e.stopPropagation()}
                >
                  <hex-color-picker
                    .color=${finalLineColor}
                    data-index=${index}
                    data-field="line_color"
                    @color-changed=${this._entityAttributeChanged}
                  ></hex-color-picker>
                </div>
              </div>
            `
          : this._renderEntityThresholdsEditor(index)}
      </div>
    `;
  }

  private _renderEntityThresholdsEditor(entityIndex: number): TemplateResult {
    const entityConf = this._config.entities[entityIndex];
    if (!entityConf) return html``;

    return html`
      <div>
        <h4>${localize(this.hass, 'component.bge.editor.color_thresholds')}</h4>
        <div class="entities-container">
          ${(entityConf.color_thresholds || []).map(
            (threshold, index) => html`
              <div
                class="entity-container threshold-container ${this._dropThresholdIndex === index
                  ? 'drag-over'
                  : ''} ${this._draggedThresholdIndex === index ? 'dragging' : ''}"
                draggable="true"
                @dragstart=${(e: DragEvent) => this._handleThresholdDragStart(e, index)}
                @dragover=${(e: DragEvent) => this._handleThresholdDragOver(e, index)}
                @dragleave=${() => (this._dropThresholdIndex = null)}
                @drop=${(e: DragEvent) => this._handleThresholdDrop(e, entityIndex)}
                @dragend=${() => {
                  this._draggedThresholdIndex = null;
                  this._dropThresholdIndex = null;
                }}
              >
                <div class="drag-handle">
                  <ha-icon icon="mdi:drag-vertical"></ha-icon>
                </div>
                <div class="threshold-inputs">
                  <ha-textfield
                    .label=${localize(this.hass, 'component.bge.editor.value')}
                    type="number"
                    .value=${String(threshold.value)}
                    data-field="value"
                    @change=${(e: Event) => this._thresholdChanged(e, index, entityIndex)}
                  ></ha-textfield>
                  <div
                    class="color-input-wrapper"
                    data-picker-id=${`entity_${entityIndex}_threshold_${index}`}
                    @mousedown=${(e: MouseEvent) =>
                      this._toggleColorPicker(e, `entity_${entityIndex}_threshold_${index}`)}
                  >
                    <ha-textfield
                      .label=${localize(this.hass, 'component.bge.editor.color')}
                      .value=${threshold.color}
                      data-field="color"
                      @change=${(e: Event) => this._thresholdChanged(e, index, entityIndex)}
                    ></ha-textfield>
                    <div class="color-preview" style="background-color: ${threshold.color}"></div>
                    <div
                      class="color-picker-popup"
                      data-picker-id=${`entity_${entityIndex}_threshold_${index}`}
                      @mousedown=${(e: MouseEvent) => e.stopPropagation()}
                    >
                      <hex-color-picker
                        .color=${threshold.color}
                        data-field="color"
                        @color-changed=${(e: CustomEvent) => this._thresholdChanged(e, index, entityIndex)}
                      ></hex-color-picker>
                    </div>
                  </div>
                </div>
                <ha-icon-button class="remove-icon" @click=${() => this._removeThreshold(index, entityIndex)}
                  ><ha-icon icon="mdi:close"></ha-icon
                ></ha-icon-button>
              </div>
            `,
          )}
        </div>
        <ha-button class="add-threshold-button" @click=${() => this._addThreshold(entityIndex)}>
          ${localize(this.hass, 'component.bge.editor.add_threshold')}
        </ha-button>
      </div>
    `;
  }

  protected render(): TemplateResult {
    if (!this.hass || !this._config) {
      return html`<div>Waiting for config…</div>`;
    }

    if (this._editingIndex !== null) {
      return this._renderEntityEditor();
    }

    return this._renderMainConfig();
  }

  private _renderMainConfig(): TemplateResult {
    const colorMode = (this._config.color_thresholds?.length ?? 0) > 0 ? 'threshold' : 'single';
    const isDarkMode = this.hass.themes?.darkMode ?? false;
    const defaultLineColor = isDarkMode ? 'white' : 'black';

    return html`
      <div class="card-config">
        <h3>${localize(this.hass, 'component.bge.editor.general')}</h3>
        <div class="side-by-side">
          <ha-textfield
            .label=${localize(this.hass, 'component.bge.editor.title')}
            .value=${this._config.title || ''}
            .configValue=${'title'}
            @change=${this._valueChanged}
          ></ha-textfield>
        </div>

        <h3>${localize(this.hass, 'component.bge.editor.layout')}</h3>
        <ha-formfield .label=${localize(this.hass, 'component.bge.editor.tile_style')}>
          <ha-switch
            .checked=${this._config.tile_style === true}
            .configValue=${'tile_style'}
            @change=${this._valueChanged}
          ></ha-switch>
        </ha-formfield>
        <ha-formfield .label=${localize(this.hass, 'component.bge.editor.show_icon')}>
          <ha-switch
            .checked=${this._config.show_icon !== false}
            .configValue=${'show_icon'}
            @change=${this._valueChanged}
          ></ha-switch>
        </ha-formfield>

        <h3>${localize(this.hass, 'component.bge.editor.graph_appearance')}</h3>
        <div class="side-by-side">
          <ha-textfield
            .label=${localize(this.hass, 'component.bge.editor.hours_to_show')}
            type="number"
            .value=${String(this._config.hours_to_show ?? 24)}
            .configValue=${'hours_to_show'}
            @change=${this._valueChanged}
          ></ha-textfield>

          <ha-textfield
            .label=${localize(this.hass, 'component.bge.editor.line_width')}
            type="number"
            .value=${String(this._config.line_width ?? 3)}
            .configValue=${'line_width'}
            @change=${this._valueChanged}
          ></ha-textfield>
        </div>

        <div class="side-by-side">
          <div class="dropdown-wrapper" style="margin-top: 8px;">
            <ha-dropdown
              @wa-select=${(ev: CustomEvent) => {
                const target = { configValue: 'line_length', value: ev.detail.item.value } as unknown as EventTarget;
                this._valueChanged({ target } as unknown as Event);
              }}
            >
              <div slot="trigger" class="dropdown-trigger">
                <ha-textfield
                  readonly
                  .label=${localize(this.hass, 'component.bge.editor.line_length')}
                  .value=${this._config.line_length === 'short'
                    ? localize(this.hass, 'component.bge.editor.line_length_short')
                    : localize(this.hass, 'component.bge.editor.line_length_long')}
                  iconTrailing
                  class="dropdown-textfield"
                >
                  <ha-icon slot="trailingIcon" icon="mdi:menu-down"></ha-icon>
                </ha-textfield>
              </div>
              <ha-dropdown-item value="long"
                >${localize(this.hass, 'component.bge.editor.line_length_long')}</ha-dropdown-item
              >
              <ha-dropdown-item value="short"
                >${localize(this.hass, 'component.bge.editor.line_length_short')}</ha-dropdown-item
              >
            </ha-dropdown>
          </div>
          <div class="dropdown-wrapper" style="margin-top: 8px;">
            <ha-dropdown
              @wa-select=${(ev: CustomEvent) => {
                const target = { configValue: 'curve', value: ev.detail.item.value } as unknown as EventTarget;
                this._valueChanged({ target } as unknown as Event);
              }}
            >
              <div slot="trigger" class="dropdown-trigger">
                <ha-textfield
                  readonly
                  .label=${localize(this.hass, 'component.bge.editor.curve')}
                  .value=${this._config.curve === 'linear'
                    ? localize(this.hass, 'component.bge.editor.curve_linear')
                    : this._config.curve === 'natural'
                      ? localize(this.hass, 'component.bge.editor.curve_natural')
                      : this._config.curve === 'step'
                        ? localize(this.hass, 'component.bge.editor.curve_step')
                        : localize(this.hass, 'component.bge.editor.curve_spline')}
                  iconTrailing
                  class="dropdown-textfield"
                >
                  <ha-icon slot="trailingIcon" icon="mdi:menu-down"></ha-icon>
                </ha-textfield>
              </div>
              <ha-dropdown-item value="spline"
                >${localize(this.hass, 'component.bge.editor.curve_spline')}</ha-dropdown-item
              >
              <ha-dropdown-item value="linear"
                >${localize(this.hass, 'component.bge.editor.curve_linear')}</ha-dropdown-item
              >
              <ha-dropdown-item value="natural"
                >${localize(this.hass, 'component.bge.editor.curve_natural')}</ha-dropdown-item
              >
              <ha-dropdown-item value="step"
                >${localize(this.hass, 'component.bge.editor.curve_step')}</ha-dropdown-item
              >
            </ha-dropdown>
          </div>
        </div>

        <ha-formfield .label=${localize(this.hass, 'component.bge.editor.line_glow')}>
          <ha-switch
            .checked=${this._config.line_glow === true}
            .configValue=${'line_glow'}
            @change=${this._valueChanged}
          ></ha-switch>
        </ha-formfield>

        ${this._renderGraphBoundsEditor(this._config, this._valueChanged)}

        <div class="opacity-slider-container">
          <div class="label-container">
            <span>${localize(this.hass, 'component.bge.editor.line_opacity')}</span>
            <span>${Number(this._config.line_opacity ?? 0.2).toFixed(3)}</span>
          </div>
          <ha-slider
            min="0.05"
            max="0.8"
            step="0.025"
            .value=${this._config.line_opacity ?? 0.2}
            .configValue=${'line_opacity'}
            @change=${this._valueChanged}
            pin
          ></ha-slider>
        </div>

        <div class="side-by-side">
          <div class="dropdown-wrapper" style="margin-top: 8px;">
            <ha-dropdown
              @wa-select=${(ev: CustomEvent) => {
                const target = { value: ev.detail.item.value };
                this._handleColorModeChange({ target } as unknown as Event, null);
              }}
            >
              <div slot="trigger" class="dropdown-trigger">
                <ha-textfield
                  readonly
                  .label=${localize(this.hass, 'component.bge.editor.color_mode')}
                  .value=${colorMode === 'single'
                    ? localize(this.hass, 'component.bge.editor.color_mode_single')
                    : localize(this.hass, 'component.bge.editor.color_mode_threshold')}
                  iconTrailing
                  class="dropdown-textfield"
                >
                  <ha-icon slot="trailingIcon" icon="mdi:menu-down"></ha-icon>
                </ha-textfield>
              </div>
              <ha-dropdown-item value="single"
                >${localize(this.hass, 'component.bge.editor.color_mode_single')}</ha-dropdown-item
              >
              <ha-dropdown-item value="threshold"
                >${localize(this.hass, 'component.bge.editor.color_mode_threshold')}</ha-dropdown-item
              >
            </ha-dropdown>
          </div>
        </div>

        ${colorMode === 'single'
          ? html`
              <div
                class="color-input-wrapper"
                data-picker-id="line_color"
                @mousedown=${(e: MouseEvent) => this._toggleColorPicker(e, 'line_color')}
              >
                <ha-textfield
                  .label=${localize(this.hass, 'component.bge.editor.line_color')}
                  .value=${this._config.line_color || defaultLineColor}
                  .configValue=${'line_color'}
                  @change=${this._valueChanged}
                ></ha-textfield>
                <div
                  class="color-preview"
                  style="background-color: ${this._config.line_color || defaultLineColor}"
                ></div>
                <div
                  class="color-picker-popup"
                  data-picker-id="line_color"
                  @mousedown=${(e: MouseEvent) => e.stopPropagation()}
                >
                  <hex-color-picker
                    .color=${this._config.line_color || defaultLineColor}
                    .configValue=${'line_color'}
                    @color-changed=${this._colorPicked}
                  ></hex-color-picker>
                </div>
              </div>
            `
          : html`
              <div>
                <h3>${localize(this.hass, 'component.bge.editor.color_thresholds')}</h3>
                <div class="entities-container">
                  ${(this._config.color_thresholds || []).map(
                    (threshold, index) => html`
                      <div
                        class="entity-container threshold-container ${this._dropThresholdIndex === index
                          ? 'drag-over'
                          : ''} ${this._draggedThresholdIndex === index ? 'dragging' : ''}"
                        draggable="true"
                        @dragstart=${(e: DragEvent) => this._handleThresholdDragStart(e, index)}
                        @dragover=${(e: DragEvent) => this._handleThresholdDragOver(e, index)}
                        @dragleave=${() => (this._dropThresholdIndex = null)}
                        @drop=${(e: DragEvent) => this._handleThresholdDrop(e, null)}
                        @dragend=${() => {
                          this._draggedThresholdIndex = null;
                          this._dropThresholdIndex = null;
                        }}
                      >
                        <div class="drag-handle">
                          <ha-icon icon="mdi:drag-vertical"></ha-icon>
                        </div>
                        <div class="threshold-inputs">
                          <ha-textfield
                            .label=${localize(this.hass, 'component.bge.editor.value')}
                            type="number"
                            .value=${String(threshold.value)}
                            data-field="value"
                            @change=${(e: Event) => this._thresholdChanged(e, index, null)}
                          ></ha-textfield>
                          <div
                            class="color-input-wrapper"
                            data-picker-id=${`threshold_${index}`}
                            @mousedown=${(e: MouseEvent) => this._toggleColorPicker(e, `threshold_${index}`)}
                          >
                            <ha-textfield
                              .label=${localize(this.hass, 'component.bge.editor.color')}
                              .value=${threshold.color}
                              data-field="color"
                              data-index=${String(index)}
                              @change=${(e: Event) => this._thresholdChanged(e, index, null)}
                            ></ha-textfield>
                            <div class="color-preview" style="background-color: ${threshold.color}"></div>
                            <div
                              class="color-picker-popup"
                              data-picker-id=${`threshold_${index}`}
                              @mousedown=${(e: MouseEvent) => e.stopPropagation()}
                            >
                              <hex-color-picker
                                .color=${threshold.color}
                                data-field="color"
                                @color-changed=${(e: CustomEvent) => this._thresholdChanged(e, index, null)}
                              ></hex-color-picker>
                            </div>
                          </div>
                        </div>
                        <ha-icon-button class="remove-icon" @click=${() => this._removeThreshold(index, null)}
                          ><ha-icon icon="mdi:close"></ha-icon
                        ></ha-icon-button>
                      </div>
                    `,
                  )}
                </div>
                <ha-button @click=${() => this._addThreshold(null)}>
                  ${localize(this.hass, 'component.bge.editor.add_threshold')}
                </ha-button>
              </div>
            `}

        <h3>${localize(this.hass, 'component.bge.editor.data_settings')}</h3>
        <div class="side-by-side">
          <ha-textfield
            .label=${localize(this.hass, 'component.bge.editor.points_per_hour')}
            type="number"
            .value=${String(this._config.points_per_hour ?? 1)}
            .configValue=${'points_per_hour'}
            @change=${this._valueChanged}
          ></ha-textfield>
          <ha-textfield
            .label=${localize(this.hass, 'component.bge.editor.update_interval')}
            type="number"
            .value=${String(this._config.update_interval ?? 600)}
            .configValue=${'update_interval'}
            @change=${this._valueChanged}
          ></ha-textfield>
        </div>

        <h3>${localize(this.hass, 'component.bge.editor.entities')}</h3>

        <div class="entities-container">
          ${this._config.entities.map(
            (entity, index) => html`
              <div
                class="entity-container ${this._dropIndex === index ? 'drag-over' : ''} ${this._draggedIndex === index
                  ? 'dragging'
                  : ''}"
                @dragover=${(e: DragEvent) => this._handleDragOver(e, index)}
                @dragleave=${this._handleDragLeave}
                @drop=${this._handleDrop}
                @dragend=${this._handleDragEnd}
              >
                <div
                  class="drag-handle"
                  draggable="true"
                  @dragstart=${(e: DragEvent) => this._handleDragStart(e, index)}
                >
                  <ha-icon icon="mdi:drag-vertical"></ha-icon>
                </div>
                <div class="entity-content">
                  <div class="entity-main">
                    <ha-entity-picker
                      .hass=${this.hass}
                      .value=${entity.entity}
                      data-index=${index}
                      data-field="entity"
                      @mousedown=${(e: MouseEvent) => e.stopPropagation()}
                      @value-changed=${this._entityAttributeChanged}
                      allow-custom-entity
                    ></ha-entity-picker>
                    <ha-icon-button
                      class="edit-icon"
                      @mousedown=${(e: MouseEvent) => e.stopPropagation()}
                      @click=${() => this._editEntity(index)}
                      ><ha-icon icon="mdi:pencil"></ha-icon
                    ></ha-icon-button>
                    <ha-icon-button
                      class="remove-icon"
                      @mousedown=${(e: MouseEvent) => e.stopPropagation()}
                      @click=${() => this._removeEntity(index)}
                      ><ha-icon icon="mdi:close"></ha-icon
                    ></ha-icon-button>
                  </div>
                </div>
              </div>
            `,
          )}
        </div>
        <ha-button class="add-entity-button" @click=${this._addEntity}>
          ${localize(this.hass, 'component.bge.editor.add_entity')}
        </ha-button>
      </div>
    `;
  }

  static styles = css`
    ${unsafeCSS(editorStyles)}
  `;
}
